import { useState, useRef } from 'react';
import emailjs from '@emailjs/browser';
import './Contact.css';

// ─────────────────────────────────────────────────────────────
//  🔑  TUMHARE EMAILJS IDs — YAHI WALE USE KARO
// ─────────────────────────────────────────────────────────────
const EMAILJS_SERVICE_ID  = 'service_sewgtxf';
const EMAILJS_TEMPLATE_ID = 'template_zxjeqvp';
const EMAILJS_PUBLIC_KEY  = 'LgJvRXiMjHl5kiiTT';
// ─────────────────────────────────────────────────────────────

const initialForm = { name: '', email: '', message: '' };

const validate = (form) => {
  const errors = {};
  if (!form.name.trim())
    errors.name = 'Name is required.';
  if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/))
    errors.email = 'Please enter a valid email.';
  if (form.message.trim().length < 10)
    errors.message = 'Message must be at least 10 characters.';
  return errors;
};

const Contact = () => {
  const formRef              = useRef(null);
  const [form,    setForm]   = useState(initialForm);
  const [errors,  setErrors] = useState({});
  const [sent,    setSent]   = useState(false);
  const [loading, setLoading]= useState(false);
  const [failed,  setFailed] = useState(false);
  const [errMsg,  setErrMsg] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: '' }));
    if (failed) setFailed(false);
  };

  const handleSubmit = () => {
    const errs = validate(form);
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setErrors({});
    setLoading(true);
    setFailed(false);
    setErrMsg('');

    // @emailjs/browser — sendForm uses actual <form> ref OR send() uses plain object
    emailjs.send(
      EMAILJS_SERVICE_ID,
      EMAILJS_TEMPLATE_ID,
      {
        from_name: form.name,
        from_email: form.email,
        message:    form.message,
        reply_to:   form.email,
      },
      EMAILJS_PUBLIC_KEY          // ← new package expects key as 4th arg here
    )
    .then(() => {
      setLoading(false);
      setSent(true);
      setForm(initialForm);
    })
    .catch((error) => {
      console.error('EmailJS Error:', error);
      setLoading(false);
      setFailed(true);
      setErrMsg(error?.text || error?.message || 'Unknown error. Check console.');
    });
  };

  return (
    <section id="contact" className="section-wrap contact-section">
      <div className="section-label">// 05. contact</div>
      <h2 className="section-title">Get In <em>Touch</em></h2>
      <div className="divider" />

      <div className="contact-wrap">

        {/* ── Left: Info ── */}
        <div className="contact-info reveal">
          <p>
            I'm currently open to new opportunities. Whether you have a project
            in mind, a question, or just want to say hello — my inbox is always open!
          </p>

          <div className="contact-details">
            <div className="contact-item">
              <span className="contact-icon">📧</span>
              <span>siddharthatiwari1705@gmail.com</span>
            </div>
            <div className="contact-item">
              <span className="contact-icon">📍</span>
              <span>India</span>
            </div>
            <div className="contact-item">
              <span className="contact-icon">⚡</span>
              <span>Usually replies within 24 hours</span>
            </div>
          </div>

          <div className="social-links">
            <a href="https://github.com/siddhartha-tiwari" className="social-btn" target="_blank" rel="noreferrer">
              <GithubIcon /> GitHub
            </a>
            <a href="https://linkedin.com/in/siddhartha-tiwari" className="social-btn" target="_blank" rel="noreferrer">
              <LinkedinIcon /> LinkedIn
            </a>
          </div>
        </div>

        {/* ── Right: Form ── */}
        <div className="contact-form reveal" style={{ transitionDelay: '0.15s' }}>

          {sent ? (
            <div className="form-success">
              <span className="success-icon">✓</span>
              <div>
                <strong>Message Sent Successfully!</strong>
                <p>Thanks for reaching out. I'll get back to you within 24 hours!</p>
              </div>
            </div>
          ) : (
            <div ref={formRef}>
              {failed && (
                <div className="form-failed">
                  <strong>❌ Error:</strong> {errMsg || 'EmailJS template variables check karo — neeche steps dekho.'}
                </div>
              )}

              <div className="form-group">
                <label htmlFor="name">Name</label>
                <input
                  id="name" name="name"
                  placeholder="Your Full Name"
                  value={form.name}
                  onChange={handleChange}
                  className={errors.name ? 'input-error' : ''}
                  disabled={loading}
                />
                {errors.name && <span className="field-error">{errors.name}</span>}
              </div>

              <div className="form-group">
                <label htmlFor="email">Email</label>
                <input
                  id="email" name="email" type="email"
                  placeholder="your@email.com"
                  value={form.email}
                  onChange={handleChange}
                  className={errors.email ? 'input-error' : ''}
                  disabled={loading}
                />
                {errors.email && <span className="field-error">{errors.email}</span>}
              </div>

              <div className="form-group">
                <label htmlFor="message">Message</label>
                <textarea
                  id="message" name="message" rows={5}
                  placeholder="Tell me about your project or idea..."
                  value={form.message}
                  onChange={handleChange}
                  className={errors.message ? 'input-error' : ''}
                  disabled={loading}
                />
                {errors.message && <span className="field-error">{errors.message}</span>}
              </div>

              <button
                className={`btn-primary submit-btn ${loading ? 'loading' : ''}`}
                onClick={handleSubmit}
                disabled={loading}
              >
                {loading
                  ? <span className="btn-loading"><span className="spinner" /> Sending...</span>
                  : 'Send Message →'
                }
              </button>
            </div>
          )}
        </div>
      </div>
    </section>
  );
};

